const cookiesContainer = document.getElementById("cookies-container");
const cookieForm = document.getElementById("cookie-form");
const cookieNameInput = document.getElementById("cookie-name");
const cookieValueInput = document.getElementById("cookie-value");
const storeButton = document.getElementById("store-button");

// Get stored cookies from local storage
const storedCookies = JSON.parse(localStorage.getItem("cookies")) || [];

// Display stored cookies
storedCookies.forEach((cookie) => {
    const cookieElement = document.createElement("div");
    cookieElement.classList.add("p-4", "mb-2", "bg-white", "rounded-md", "shadow-md");
    cookieElement.innerHTML = `Cookie Name: ${cookie.name}, Value: ${cookie.value}`;
    const editButton = document.createElement("button");
    editButton.textContent = "Edit";
    editButton.onclick = () => editCookie(cookie);
    const deleteButton = document.createElement("button");
    deleteButton.textContent = "Delete";
    deleteButton.onclick = () => deleteCookie(cookie);
    cookieElement.appendChild(editButton);
    cookieElement.appendChild(deleteButton);
    cookiesContainer.appendChild(cookieElement);
});

// Handle store form submission
cookieForm.addEventListener("submit", (e) => {
    e.preventDefault();
    const cookieName = cookieNameInput.value;
    const cookieValue = cookieValueInput.value;
    if (validateCookieName(cookieName) && validateCookieValue(cookieValue)) {
        const newCookie = {name: cookieName, value: cookieValue};
        storedCookies.push(newCookie);
        localStorage.setItem("cookies", JSON.stringify(storedCookies));
        storeCookie(newCookie);
    }
});

// Edit cookie function
function editCookie(cookie) {
    cookieNameInput.value = cookie.name;
    cookieValueInput.value = cookie.value;
    const existingCookieElement = document.querySelector(".p-4.mb-2.bg-white.rounded-md.shadow-md":contains(${cookie.name}));
    existingCookieElement.remove();
}

// Delete cookie function
function deleteCookie(cookie) {
    storedCookies = storedCookies.filter((c) => c !== cookie);
    localStorage.setItem("cookies", JSON.stringify(storedCookies));
    const cookieElement = document.querySelector(".p-4.mb-2.bg-white.rounded-md.shadow-md":contains(${cookie.name}));
    cookieElement.remove();
}

// Store cookie function
function storeCookie(cookie) {
    const cookieElement = document.createElement("div");
    cookieElement.classList.add("p-4", "mb-2", "bg-white", "rounded-md", "shadow-md");
    cookieElement.innerHTML = `Cookie Name: ${cookie.name}, Value: ${cookie.value}`;
    const editButton = document.createElement("button");
    editButton.textContent = "Edit";
    editButton.onclick = () => editCookie(cookie);
    const deleteButton = document.createElement("button");
    deleteButton.textContent = "Delete";
    deleteButton.onclick = () => deleteCookie(cookie);
    cookieElement.appendChild(editButton);
    cookieElement.appendChild(deleteButton);
    cookiesContainer.appendChild(cookieElement);
}

// Validate cookie name function
function validateCookieName(name) {
    return name.trim() !== "" && name.length <= 50;
}

// Validate cookie value function
function validateCookieValue(value) {
    return value.trim() !== "";
}
